#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[0] != y[0]) return x[0] - y[0];
    return x[1] - y[1];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L, R, k;
        long long n;
        scanf("%d %d %d %lld", &L, &R, &k, &n);
        int max_len = 0;
        int **progressions = NULL;
        int *len = NULL;
        int count = 0;
        for (int d = k; d <= R - L; d++) {
            int len_d = (R - L) / d + 1;
            if (len_d > max_len) {
                max_len = len_d;
                progressions = (int **)realloc(progressions, max_len * sizeof(int *));
                len = (int *)realloc(len, max_len * sizeof(int));
                count = 0;
            }
            if (len_d == max_len) {
                progressions[count] = (int *)malloc(2 * sizeof(int));
                progressions[count][0] = L;
                progressions[count][1] = L + d;
                len[count] = len_d;
                count++;
            }
        }
        qsort(progressions, count, sizeof(int *), compare);
        if (n > count) {
            printf("%d 0 0\n", max_len);
        } else {
            printf("%d %d %d\n", max_len, progressions[n - 1][0], progressions[n - 1][1]);
        }
        for (int i = 0; i < count; i++) {
            free(progressions[i]);
        }
        free(progressions);
        free(len);
    }
    return 0;
}

code.C++:
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

struct Progression {
    int start;
    int diff;
};

bool compare(const Progression &a, const Progression &b) {
    if (a.start != b.start) return a.start < b.start;
    return a.diff < b.diff;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int L, R, k;
        long long n;
        cin >> L >> R >> k >> n;
        int max_len = 0;
        vector<Progression> progressions;
        for (int d = k; d <= R - L; d++) {
            int len_d = (R - L) / d + 1;
            if (len_d > max_len) {
                max_len = len_d;
                progressions.clear();
            }
            if (len_d == max_len) {
                Progression p;
                p.start = L;
                p.diff = d;
                progressions.push_back(p);
            }
        }
        sort(progressions.begin(), progressions.end(), compare);
        if (n > progressions.size()) {
            cout << max_len << " 0 0" << endl;
        } else {
            cout << max_len << " " << progressions[n - 1].start << " " << progressions[n - 1].start + progressions[n - 1].diff << endl;
        }
    }
    return 0;
}

