import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            int k = sc.nextInt();
            long n = sc.nextLong();
            int max_len = 0;
            int[][] progressions = new int[R - L + 1][2];
            int count = 0;
            for (int d = k; d <= R - L; d++) {
                int len_d = (R - L) / d + 1;
                if (len_d > max_len) {
                    max_len = len_d;
                    count = 0;
                }
                if (len_d == max_len) {
                    progressions[count][0] = L;
                    progressions[count][1] = L + d;
                    count++;
                }
            }
            Arrays.sort(progressions, 0, count, (a, b) -> a[0] - b[0]);
            if (n > count) {
                System.out.println(max_len + " 0 0");
            } else {
                System.out.println(max_len + " " + progressions[(int) n - 1][0] + " " + progressions[(int) n - 1][1]);
            }
        }
    }
}

